async function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function fetchValue(): Promise<number> {
  await delay(1);
  return 42;
}

export async function getDoubledValue(): Promise<number> {
  // BUG: not awaiting fetchValue — this returns a Promise, not a number
  const value = fetchValue();
  return (value as unknown as number) * 2;
}

